"use client";
import React, { useState } from "react";
import { collection, addDoc, getDoc } from "firebase/firestore";
import { db } from "../../lib/firebase";
import { doc, setDoc, getDocs } from "firebase/firestore";
import { useRouter } from "next/navigation";
import { useSearchParams } from "next/navigation";
import { useEffect } from "react";
export default function SimpleForm() {
  const searchParams = useSearchParams();
  const id = searchParams.get("id"); // customer id
  const type = searchParams.get("type");
  const navigator = useRouter();

  //fetch data
  useEffect(() => {
    if (!id || !type) return;

    const fetchData = async () => {
      try {
        const ref = doc(db, "customers", id, "measurement", type);
        const snap = await getDoc(ref);

        if (snap.exists()) {
          setFormData((prev) => ({
            ...prev,
            ...snap.data(),
            type: type,
          }));
        } else {
          // 👉 if no data → clear form
          setFormData((prev) => ({
            ...prev,
            type: type,
            _2: "",
            _3: "",
            _4: "",
            _5: "",
            _6: "",
            _7: "",
            _8: "",
            _9: "",
            _10: "",
            _11: "",
            _12: "",
            _13: "",
            _14: "",
            _15: "",
            _16: "",
            _17: "",
          }));
        }
      } catch (error) {
        console.log(error);
      }
    };

    fetchData();
  }, [id, type]);
  //form state
  const initialState = {
    customerId: "",
    _1: "",
    type: "dress",
    _2: "",
    _3: "",
    _4: "",
    _5: "",
    _6: "",
    _7: "",
    _8: "",
    _9: "",
    _10: "",
    _11: "",
    _12: "",
    _13: "",
    _14: "",
    _15: "",
    _16: "",
    _17: "",
  };

  const [formData, setFormData] = useState(initialState);
  const clearForm = () => {
    setFormData(initialState);
  };
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const customerName = formData._1?.trim();

    if (!customerName) {
      alert("Customer name required");
      return;
    }

    try {
      const docId = customerName.toLowerCase().replace(/\s+/g, "_");

      const customerRef = doc(db, "customers", docId);

      // ✅ create customer if not exists
      const customerSnap = await getDoc(customerRef);

      if (!customerSnap.exists()) {
        await setDoc(customerRef, {
          name: customerName,
        });
      }

      // 🔥 IMPORTANT CHANGE HERE
      const measurementRef = doc(
        db,
        "customers",
        docId,
        "measurement",
        formData.type, // 👈 dress / blouse as ID
      );

      const measurementSnap = await getDoc(measurementRef);

      // ✅ check duplicate properly
      if (measurementSnap.exists()) {
        alert(`${formData.type} already exists`);
        return;
      }

      // ✅ save (no duplicate possible now)
      await setDoc(measurementRef, {
        ...formData,
        createdAt: new Date(),
      });

      alert("Saved successfully");
      clearForm();
    } catch (error) {
      console.log(error);
      alert("Error saving data");
    }
  };

  const handleUpdate = async () => {
    const customerName = formData._1?.trim();

    if (!customerName) {
      alert("Customer name required");
      return;
    }

    try {
      const docId = customerName.toLowerCase().replace(/\s+/g, "_");

      const measurementRef = doc(
        db,
        "customers",
        docId,
        "measurement",
        formData.type,
      );

      const snap = await getDoc(measurementRef);

      // ❌ if not exists → can't update
      if (!snap.exists()) {
        alert("No existing record found to update");
        return;
      }

      // ✅ update existing
      await setDoc(
        measurementRef,
        {
          ...formData,
          updatedAt: new Date(),
        },
        { merge: true },
      );

      alert("Updated successfully");
    } catch (error) {
      console.log(error);
      alert("Error updating data");
    }
  };
  return (
    <form onSubmit={handleSubmit} className="mt-40 mb-30 p-4 space-y-3">
      {/* Customer Name (using _1 as name like your system) */}
      <input
        type="text"
        name="_1"
        placeholder="Customer Name"
        value={formData._1}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      {/* Type selection */}
      <div className="flex gap-4">
        {/* Dress Button */}
        <button
          type="button"
          onClick={() =>
            navigator.push(`/admin2/NewCustomerRecorde?id=${id}&type=dress`)
          }
          className={`px-4 py-2 rounded border transition ${
            formData.type === "dress"
              ? "bg-[#d4af37] text-[#343a40] border-[#d4af37]"
              : "bg-transparent text-gray-400 border-gray-500"
          }`}
        >
          Dress
        </button>

        {/* Blouse Button */}
        <button
          type="button"
          onClick={() =>
            navigator.push(
              `/admin2/NewCustomerRecordBlouse?id=${id}&type=blouse`,
            )
          }
          className={`px-4 py-2 rounded border transition ${
            formData.type === "blouse"
              ? "bg-[#343a40] text-[#d4af37] border-[#d4af37]"
              : "bg-transparent text-gray-400 border-gray-500"
          }`}
        >
          Blouse
        </button>
      </div>
      {/* Generate inputs _2 to _17 automatically */}
      <input
        type="text"
        name="_2"
        placeholder="Field _2"
        value={formData._2}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_3"
        placeholder="Field _3"
        value={formData._3}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_4"
        placeholder="Field _4"
        value={formData._4}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_5"
        placeholder="Field _5"
        value={formData._5}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_6"
        placeholder="Field _6"
        value={formData._6}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_7"
        placeholder="Field _7"
        value={formData._7}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_8"
        placeholder="Field _8"
        value={formData._8}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_9"
        placeholder="Field _9"
        value={formData._9}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_10"
        placeholder="Field _10"
        value={formData._10}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_11"
        placeholder="Field _11"
        value={formData._11}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_12"
        placeholder="Field _12"
        value={formData._12}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_13"
        placeholder="Field _13"
        value={formData._13}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_14"
        placeholder="Field _14"
        value={formData._14}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_15"
        placeholder="Field _15"
        value={formData._15}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <textarea
        name="_16"
        placeholder="Notes"
        value={formData._16}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      <input
        type="text"
        name="_17"
        placeholder="Field _17"
        value={formData._17}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      {/* Textarea (_16 already included above but if you want special) */}
      <textarea
        name="_16"
        placeholder="Notes"
        value={formData._16}
        onChange={handleChange}
        className="border p-2 w-full"
      />

      {/* Buttons */}
      <div className="flex gap-3">
        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded"
        >
          Save
        </button>

        <button
          type="button"
          onClick={clearForm}
          className="bg-gray-400 text-white px-4 py-2 rounded"
        >
          Reset
        </button>
        <button
          type="button"
          onClick={handleUpdate}
          className="bg-blue-600 text-white px-4 py-2 rounded"
        >
          Save
        </button>
      </div>
    </form>
  );
}
